<template>
	<view class="container">
		<!-- 情景选择 -->
		<view class="scene-box">
			<view 
				class="model-box" 
				v-for="(item,index) in sceneList" 
				:key="index" 
				@click="statusChange(index)"
			>
				<view class="img-box">
					<image :src="item.activePath" alt="" v-if="item.status">
					<image :src="item.path" alt="" v-else>
				</view>
				<view class="name-box" :class="{'acitve-name':item.status}">{{item.name}}</view>
			</view>
		</view>
		<!-- 悬架、侧倾设置 -->
		<view class="car-box">
			<!-- 背景 -->
			<image class="car-back" src="/static/backImage/carBack.png" mode=""></image>
			<!-- 悬架、侧倾 -->
			<view v-for="(item,index) in gaugeList" :key="index" class="suspension" :class="{'behind-suspension':item.mainRotate}">
				<image class="btn left" :src="item.btnImgSrc" mode=""  @click="gaugeAction('reduce',index)"></image>
				<view class="suspension-box">
					<image class="gauge-img" :class="{'behind':item.gaugeImgRotate}" :src="item.gaugeImgSrc" mode=""></image>
					<view 
						:class="{
							'suspension-name':item.progressType=='front',
							'heel-name':item.progressType=='heel',
							'behind-suspension-name':item.progressType=='behind'
						}"
					>{{item.name}}</view>
					<image v-if="item.progress>0" class="progress-img" :class="{'behind':item.progressImgRotate}" :src="item.progressImgSrc+item.progress+'.png'" mode=""></image>
				</view>
				<image class="btn" :src="item.btnImgSrc" mode="" @click="gaugeAction('add',index)"></image>
			</view>
			<!-- 重置 -->
			<view class="action-btn-box action-reset" @click="reset">
				<view class="action-btn">
					<image class="icon-img" src="/static/iconImage/Reset.png" mode=""></image>
					<view class="action-content">点击重置</view>
				</view>
			</view>
			<!-- 应用 -->
			<view class="action-btn-box action-apply" @click="apply">
				<view class="action-btn">
					<image class="icon-img" src="/static/iconImage/click.png" mode=""></image>
					<view class="action-content">点击应用</view>
				</view>
			</view>
		</view>
		
		<!-- 拉伸压缩 -->
		<view class="draw-compress-box">
			<view class="draw-compress-title">拉伸压缩</view>
			<view class="draw-compress-content">
				<image class="btn-image" src="/static/iconImage/reduce.png" mode="" @click="drawAction('reduce')"></image>
				<view class="progress-box">
					<image class="empty-progress" src="/static/drawCompress/progressEmpty.png" mode=""></image>
					<image v-if="drawProgress>0" class="progress" :src="'/static/drawCompress/progress_'+drawProgress+'.png'" mode=""></image>
				</view>
				<image class="btn-image" src="/static/iconImage/add.png" mode="" @click="drawAction('add')"></image>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				sceneList:[
					{
						name:"公路",
						path:"/static/iconImage/highway.png",
						activePath:"/static/iconImage/highway_active.png",
						status:false
					},
					{
						name:"湿地",
						path:"/static/iconImage/wetland.png",
						activePath:"/static/iconImage/wetland_active.png",
						status:false
					},
					{
						name:"沙漠",
						path:"/static/iconImage/desert.png",
						activePath:"/static/iconImage/desert_active.png",
						status:false
					}
				],
				gaugeList:[
					{
						name:"前悬架",
						mainRotate:false,
						btnImgSrc:"/static/suspension/blueArrow.png",
						gaugeImgRotate:false,
						gaugeImgSrc:"/static/suspension/suspension.png",
						progressImgRotate:true,
						progressImgSrc:"/static/suspension/progress_",
						progressType:"front",
						progress:0
					},
					{
						name:"侧倾",
						mainRotate:false,
						btnImgSrc:"/static/heel/redArrow.png",
						gaugeImgRotate:false,
						gaugeImgSrc:"/static/heel/heel.png",
						progressImgRotate:false,
						progressImgSrc:"/static/heel/progress_",
						progressType:"heel",
						progress:0
					},
					{
						name:"后悬架",
						mainRotate:true,
						btnImgSrc:"/static/suspension/blueArrow.png",
						gaugeImgRotate:true,
						gaugeImgSrc:"/static/suspension/suspension.png",
						progressImgRotate:false,
						progressImgSrc:"/static/suspension/progress_",
						progressType:"behind",
						progress:0
					}
				],
				drawProgress:0
			}
		},
		onShow() {
			uni.hideTabBar({
				animation: false
			})
		},
		methods: {
			statusChange(index){
				const status = this.sceneList[index].status;
				this.sceneList[index].status = !status;
			},
			gaugeAction(type,index){
				const num = this.gaugeList[index].progress;
				if(type=="add"){
					num<9?this.gaugeList[index].progress += 1:null;
				}else if(type=="reduce"){
					num>0?this.gaugeList[index].progress -= 1:null;
				}
				this.gaugeList.reverse().reverse();
			},
			reset(){
				this.gaugeList.forEach(element=>{
					element.progress=0;
				})
				this.drawProgress=0;
			},
			apply(){
				uni.showToast({
					title: '已应用',
					duration: 2000
				});
				setTimeout(()=>{
					uni.switchTab({
						url:"/pages/index/index"
					})
				},2000)
			},
			drawAction(type){
				const number = this.drawProgress;
				if(type=="reduce"){
					if(number>0){
						this.drawProgress -= 1;
					}
				}else if(type=="add"){
					if(number<9){
						this.drawProgress +=1;
					}
				}
			}
		}
	}
</script>

<style lang="less" scoped>
.container {
	box-sizing: border-box;
	position: relative;
	width: 100%;
	height: 100vh;
	background: #081628;
	font-size: 14px;
	line-height: 24px;
	.scene-box{
		box-sizing: border-box;
		padding: 53rpx 20rpx 0;
		display: flex;
		flex-direction: row;
		justify-content: space-around;
		align-items: center;
		width: 100%;
		.model-box{
			.img-box{
				width: 73rpx;
				height: 83rpx;
				image{
					width:100%;
					height:100%;
				}
			}
			.name-box{
				width: 100%;
				font-size: 20rpx;
				text-align: center;
				color: #A6BCDC;
			}
			.acitve-name{
				color: #0562FF;
			}
		}
	}
	.car-box{
		box-sizing: border-box;
		position: relative;
		margin-top: 3vh;
		padding: 0 40rpx;
		width: 100%;
		height: 848rpx;
		.car-back{
			position:absolute;
			left:50%;
			transform: translateX(-50%);
			display: block;
			width: 343rpx;
			height: 775rpx;
		}
		
		.suspension{
			width: 100%;
			height: 195rpx;
			display: flex;
			flex-direction: row;
			justify-content: space-around;
			align-items: center;
			.btn{
				width: 71rpx;
				height: 107rpx;
			}
			.btn.left{
				transform: rotateY(180deg);
			}
			.suspension-box{
				position: relative;
				width: 383rpx;
				height: 100%;
				.gauge-img{
					position: absolute;
					left: 0;
					width: 100%;
					height:100%;
				}
				.progress-img{
					position: absolute;
					left: 13rpx;
					width: 100%;
					height: 100%;
				}
				.behind{
					transform: rotateX(180deg);
				}
				.suspension-name,.heel-name,.behind-suspension-name{
					position: absolute;
					left: 50%;
					transform: translateX(-50%);
					font-size: 24rpx;
					font-weight: bold;
				}
				.suspension-name{
					bottom: 15%;
					color: #1DB4FF;
				}
				.heel-name{
					bottom: 15%;
					color: #F4000C;
				}
				.behind-suspension-name{
					top: 15%;
					color: #1DB4FF;
				}
			}
		}
		.behind-suspension{
			margin-top: 263rpx;
		}
		
		.action-btn-box{
			position: absolute;
			bottom:28%;
			padding: 8rpx;
			width: 61rpx;
			height: 188rpx;
			border-radius: 61rpx;
			background: linear-gradient(to bottom,#00C0FA,#053CE6);
			.action-btn{
				width: 100%;
				height: 100%;
				background-color: #081628;
				border-radius: 61rpx;
				.icon-img{
					margin:0 auto;
					padding-top: 18rpx;
					display: block;
					width: 27rpx;
					height:27rpx;
				}
				.action-content{
					margin:14rpx auto 0;
					width: 28rpx;
					font-size: 22rpx;
					line-height: 28rpx;
					text-align: center;
					color: #00C0FA;
				}
			}
		}
		.action-reset{
			left: 5%;
		}
		.action-apply{
			right:5%;
		}
	}
	.draw-compress-box{
		margin-top: 5vh;
		width: 100%;
		.draw-compress-title{
			font-size: 24rpx;
			line-height: 28rpx;
			color:#E80D16;
			text-align: center;
		}
		.draw-compress-content{
			margin-top: 20rpx;
			padding: 0 40rpx;
			display: flex;
			flex-direction: row;
			justify-content: space-around;
			align-items: center;
			.btn-image{
				width: 53rpx;
				height: 53rpx;
			}
			.progress-box{
				position: relative;
				width: 431rpx;
				height: 27rpx;
				.empty-progress{
					position: absolute;
					top: 0;
					left: 0;
					width: 100%;
					height: 100%;
				}
				.progress{
					position: absolute;
					top: 0;
					left: 0;
					width: 100%;
					height: 100%;
				}
			}
		}
	}
}
</style>
